/*==============================================================*/
/* Table: CBTPER_CAT                                            */
/*==============================================================*/
CREATE TABLE CBTPER_CAT
(
    ID_CBTPER_CAT_CODE          INT NOT NULL AUTO_INCREMENT,
    CBTPER_CAT_NAME             VARCHAR(32) NOT NULL,
    CBTPER_CAT_VALID_FROM       TIMESTAMP,
    CBTPER_CAT_VALID_TO         TIMESTAMP NULL,
    CBTPER_CAT_CREATED_BY       VARCHAR(16),
    CBTPER_CAT_UPDATED_BY       VARCHAR(16),
    CBTPER_CAT_CREATED_AT       TIMESTAMP,
    CBTPER_CAT_UPDATED_AT       TIMESTAMP,
    PRIMARY KEY (ID_CBTPER_CAT_CODE)
);

/*==============================================================*/
/* Table: CBTPER_TYPE                                           */
/*==============================================================*/
CREATE TABLE CBTPER_TYPE
(
    ID_CBTPER_TYPE          INT NOT NULL AUTO_INCREMENT,
    XID_CBTPER_CAT_CODE     INT NOT NULL,
    XID_CBTPER_CODE         INT NOT NULL,
    CBTPER_TYPE_FLAG        BOOLEAN NOT NULL,
    CBTPER_TYPE_VALID_FROM  TIMESTAMP,
    CBTPER_TYPE_VALID_TO    TIMESTAMP NULL,
    CBTPER_TYPE_CREATED_BY  VARCHAR(16),
    CBTPER_TYPE_UPDATED_BY  VARCHAR(16),
    CBTPER_TYPE_CREATED_AT  TIMESTAMP,
    CBTPER_TYPE_UPDATED_AT  TIMESTAMP,
    PRIMARY KEY (ID_CBTPER_TYPE)
);
/*==============================================================*/
/* Table: CBTPER                                                */
/*==============================================================*/
CREATE TABLE CBTPER
(
    ID_CBTPER_CODE       INT NOT NULL AUTO_INCREMENT,
    CBTMEN_CODE          INT,
    CBTPER_ROLE          VARCHAR(32) NOT NULL,
    CBTPER_VALID_FROM    TIMESTAMP,
    CBTPER_VALID_TO      TIMESTAMP NULL,
    CBTPER_CREATED_BY    VARCHAR(16),
    CBTPER_UPDATED_BY    VARCHAR(16),
    CBTPER_CREATED_AT    TIMESTAMP,
    CBTPER_UPDATED_AT    TIMESTAMP,
    PRIMARY KEY (ID_CBTPER_CODE)
);

ALTER TABLE CBTPER ADD CONSTRAINT XID_CBTPER_CODE_XID_CBTMEN_CODE FOREIGN KEY (CBTMEN_CODE)
    REFERENCES CBTMEN (CBTMEN_CODE);

ALTER TABLE CBTPER_TYPE ADD CONSTRAINT XID_CBTPER_TYPE_CODE_XID_CBTPER_CAT_CODE FOREIGN KEY (XID_CBTPER_CAT_CODE)
    REFERENCES CBTPER_CAT (ID_CBTPER_CAT_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;

ALTER TABLE CBTPER_TYPE ADD CONSTRAINT XID_CBTPER_TYPE_XID_CBTPER_CODE FOREIGN KEY (XID_CBTPER_CODE)
    REFERENCES CBTPER (ID_CBTPER_CODE) ON DELETE RESTRICT ON UPDATE RESTRICT;



